'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { reportAPI } from '@/app/lib/api';
import ScoreGauge from '@/app/components/ScoreGauge';
import DimensionRadar from '@/app/components/DimensionRadar';
import type { CareerReport } from '@/app/types';
import {
    TrendingUp,
    TrendingDown,
    DollarSign,
    Building2,
    AlertCircle,
    ArrowRight,
    Loader2,
} from 'lucide-react';
import Link from 'next/link';

export default function DashboardPage() {
    const params = useParams();
    const router = useRouter();
    const assessmentId = params.assessmentId as string;

    const [report, setReport] = useState<CareerReport | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        loadReport();
    }, [assessmentId]);

    const loadReport = async () => {
        try {
            const data = await reportAPI.get(parseInt(assessmentId));
            setReport(data);
        } catch (err) {
            setError('Failed to load report. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <Loader2 className="w-16 h-16 text-primary animate-spin" />
            </div>
        );
    }

    if (error || !report) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <div className="card max-w-md text-center">
                    <AlertCircle className="w-16 h-16 text-red-500 mx-auto mb-4" />
                    <h2 className="text-2xl font-bold text-white mb-2">Error Loading Report</h2>
                    <p className="text-gray-400 mb-6">{error}</p>
                    <button onClick={() => router.push('/')} className="btn btn-primary">
                        Go Home
                    </button>
                </div>
            </div>
        );
    }

    const getSalaryIcon = (alignment: string) => {
        if (alignment === 'Underpaid') return <TrendingDown className="text-red-500" />;
        if (alignment === 'Overpaid') return <TrendingUp className="text-green-500" />;
        return <DollarSign className="text-yellow-500" />;
    };

    const getSalaryColor = (alignment: string) => {
        if (alignment === 'Underpaid') return 'text-red-500';
        if (alignment === 'Overpaid') return 'text-green-500';
        return 'text-yellow-500';
    };

    return (
        <div className="p-8 md:p-12 space-y-12 bg-slate-50 min-h-screen">
            {/* Header */}
            <header className="flex flex-col md:flex-row md:items-end justify-between gap-6 pb-6 border-b border-slate-200">
                <div>
                    <div className="flex items-center gap-2 mb-2">
                        <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded uppercase tracking-wider">Report Active</span>
                        <span className="text-xs font-medium text-slate-400">• Generated {new Date().toLocaleDateString()}</span>
                    </div>
                    <h1 className="heading-1">Career Intelligence Report</h1>
                </div>
                <div className="flex items-center gap-3">
                    <button className="btn btn-secondary shadow-sm">
                        Share Report
                    </button>
                    <Link href={`/roadmap/${assessmentId}`} className="btn btn-primary shadow-sm">
                        View Roadmap
                        <ArrowRight className="ml-2" size={16} />
                    </Link>
                </div>
            </header>

            {/* Key Metrics Grid */}
            <section className="grid grid-cols-1 md:grid-cols-4 gap-6">
                {/* Overall Score Card */}
                <div className="card md:col-span-2 p-8 flex items-center justify-between group hover:border-indigo-200 transition-all">
                    <div>
                        <p className="text-xs font-bold uppercase tracking-wider text-slate-500 mb-4">Overall Career Score</p>
                        <div className="flex items-baseline gap-2 mb-4">
                            <span className="text-6xl font-black text-slate-900">{Math.round(report.overall_score)}</span>
                            <span className="text-slate-400 font-bold text-xl">/ 100</span>
                        </div>
                        <div className="w-full max-w-[200px] h-2 bg-slate-100 rounded-full overflow-hidden">
                            <motion.div
                                initial={{ width: 0 }}
                                animate={{ width: `${report.overall_score}%` }}
                                className="h-full bg-indigo-600"
                            />
                        </div>
                    </div>
                    <div className="hidden sm:block">
                        <ScoreGauge score={report.overall_score} size="md" label="Overall" />
                    </div>
                </div>

                {/* Readiness Card */}
                <div className="card p-6 flex flex-col justify-between">
                    <div>
                        <p className="text-xs font-bold uppercase tracking-wider text-slate-500 mb-4">Market Readiness</p>
                        <div className={`text-2xl font-bold mb-2 ${report.readiness_level === 'Ready' ? 'text-emerald-600' :
                            report.readiness_level === 'Near Ready' ? 'text-amber-600' : 'text-rose-600'
                            }`}>
                            {report.readiness_level}
                        </div>
                    </div>
                    <div className="text-xs text-slate-500 font-medium">
                        Comparison vs. industry standards for your target level.
                    </div>
                </div>

                {/* Salary Card */}
                <div className="card p-6 flex flex-col justify-between">
                    <div>
                        <p className="text-xs font-bold uppercase tracking-wider text-slate-500 mb-4">Salary Status</p>
                        <div className={`text-2xl font-bold mb-2 ${getSalaryColor(report.salary_info?.alignment || '')}`}>
                            {report.salary_info?.alignment || 'No Data'}
                        </div>
                    </div>
                    {report.salary_info && (
                        <div className="text-xs text-slate-500 font-medium">
                            Market Rate: ${report.salary_info.expected_median.toLocaleString()}
                        </div>
                    )}
                </div>
            </section>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Detailed Analysis Area */}
                <div className="lg:col-span-2 space-y-8">
                    {/* Skills Visualization */}
                    <section className="card p-8">
                        <div className="flex items-center justify-between mb-8">
                            <h2 className="heading-3">Skill Dimension Analysis</h2>
                            <span className="text-xs text-slate-400 font-medium">Institutional Benchmark Logic</span>
                        </div>
                        <div className="flex flex-col md:flex-row gap-8 items-center">
                            <div className="flex-1 w-full">
                                <DimensionRadar scores={report.dimension_scores} />
                            </div>
                            <div className="w-full md:w-64 space-y-4">
                                {report.dimension_scores.map((dim, i) => (
                                    <div key={i} className="flex items-center justify-between text-xs">
                                        <span className="text-slate-500 font-medium">{dim.dimension}</span>
                                        <span className="font-bold text-slate-700">{Math.round(dim.score)}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </section>
                </div>

                {/* Side Recommendations */}
                <aside className="space-y-6">
                    {/* Salary Detail Card */}
                    {report.salary_info && (
                        <section className="card p-6 bg-indigo-50/30 border-indigo-100">
                            <h3 className="text-sm font-bold uppercase tracking-wider text-indigo-900 mb-4">Market Opportunity</h3>
                            <div className="space-y-4">
                                <div>
                                    <p className="text-xs text-indigo-600 font-bold mb-1">Expected Range</p>
                                    <p className="text-lg font-bold text-slate-900">
                                        ${report.salary_info.expected_min.toLocaleString()} — ${report.salary_info.expected_max.toLocaleString()}
                                    </p>
                                </div>
                                {report.salary_info.gap !== undefined && report.salary_info.gap > 0 && (
                                    <div className="p-3 bg-white rounded-lg border border-indigo-100 shadow-sm">
                                        <p className="text-[10px] font-bold text-rose-500 uppercase mb-1">Potential Increase</p>
                                        <p className="text-xl font-black text-rose-600">+${report.salary_info.gap.toLocaleString()}</p>
                                    </div>
                                )}
                            </div>
                        </section>
                    )}

                    {/* Risk Flags */}
                    <section className="card p-6">
                        <h3 className="text-sm font-bold uppercase tracking-wider text-slate-500 mb-4 flex items-center gap-2">
                            <AlertCircle size={14} className="text-amber-500" />
                            Skill Gaps
                        </h3>
                        {report.weak_dimensions.length > 0 ? (
                            <div className="flex flex-wrap gap-2">
                                {report.weak_dimensions.map((dim, i) => (
                                    <span key={i} className="px-3 py-1 bg-slate-100 text-slate-700 text-xs font-bold rounded-full border border-slate-200 uppercase tracking-tighter">
                                        {dim}
                                    </span>
                                ))}
                            </div>
                        ) : (
                            <p className="text-xs text-slate-400 italic">No major risks identified.</p>
                        )}
                    </section>

                    {/* Quick Wins */}
                    <section className="card p-6">
                        <h3 className="text-sm font-bold uppercase tracking-wider text-slate-500 mb-4">Immediate Actions</h3>
                        <div className="space-y-3">
                            {report.quick_wins.map((win, i) => (
                                <div key={i} className="flex gap-3 text-xs leading-relaxed group">
                                    <div className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 shrink-0 group-hover:scale-125 transition-transform" />
                                    <span className="text-slate-600 font-medium">{win}</span>
                                </div>
                            ))}
                        </div>
                    </section>
                </aside>
            </div>
        </div>
    );
}
